theme.custom_css_code:
.mgm3-wrap {
  width: 100%;
  max-width: 1180px;
  margin: 0 auto;
  font-family: Arial, Helvetica, sans-serif;
  color: #f3f4f6;
}

.mgm3-panel {
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.09);
  border-radius: 22px;
  padding: 18px;
  box-sizing: border-box;
  backdrop-filter: blur(6px);
}

.mgm3-table-scroll {
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  margin-bottom: 18px;
}

.mgm3-table {
  width: 100%;
  min-width: 760px;
  border-collapse: collapse;
}

.mgm3-table td {
  padding: 14px 16px;
  border-bottom: 1px solid rgba(255,255,255,0.08);
  font-size: 14px;
  line-height: 1.45;
  vertical-align: top;
}

.mgm3-table tr:last-child td {
  border-bottom: 0;
}

.mgm3-table td:first-child {
  width: 34%;
  color: #c9ced6;
  font-weight: 700;
}

.mgm3-table td:last-child {
  color: #ffffff;
}

.mgm3-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 18px;
  margin-bottom: 18px;
}

.mgm3-tile {
  background: linear-gradient(180deg, rgba(255,255,255,0.05) 0%, rgba(255,255,255,0.025) 100%);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 22px;
  padding: 18px;
  min-height: 210px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
}

.mgm3-emoji {
  width: 82px;
  height: 82px;
  margin-bottom: 16px;
  border-radius: 20px;
  background: rgba(255,255,255,0.06);
  border: 1px solid rgba(255,255,255,0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 38px;
  line-height: 1;
  flex: 0 0 auto;
}

.mgm3-text strong {
  display: block;
  font-size: 18px;
  line-height: 1.2;
  margin-bottom: 10px;
  color: #fff;
}

.mgm3-text p {
  margin: 0;
  font-size: 14px;
  line-height: 1.55;
  color: #d7dbe1;
}

.mgm3-bars {
  display: grid;
  gap: 14px;
}

.mgm3-bar-row {
  display: grid;
  grid-template-columns: 180px 1fr 58px;
  gap: 14px;
  align-items: center;
}

.mgm3-bar-label {
  font-size: 14px;
  line-height: 1.3;
  color: #edf0f3;
}

.mgm3-bar-track {
  width: 100%;
  height: 14px;
  border-radius: 999px;
  background: rgba(255,255,255,0.08);
  overflow: hidden;
}

.mgm3-bar-fill {
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, #fafafa 0%, #9faaba 100%);
}

.mgm3-bar-num {
  text-align: right;
  font-size: 13px;
  font-weight: 700;
  color: #ffffff;
}

@media (max-width: 980px) {
  .mgm3-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .mgm3-bar-row {
    grid-template-columns: 150px 1fr 52px;
  }
}

@media (max-width: 640px) {
  .mgm3-panel {
    padding: 14px;
    border-radius: 16px;
  }

  .mgm3-grid {
    grid-template-columns: 1fr;
    gap: 14px;
  }

  .mgm3-tile {
    min-height: auto;
    padding: 16px;
  }

  .mgm3-bar-row {
    grid-template-columns: 1fr;
    gap: 8px;
  }

  .mgm3-bar-num {
    text-align: left;
  }

  .mgm3-table td {
    padding: 12px 14px;
    font-size: 13px;
  }

  .mgm3-emoji {
    width: 72px;
    height: 72px;
    font-size: 34px;
    border-radius: 18px;
  }
}
